sys_script_client.script:
function onSubmit() {
    // we will first convert our date strings to date objects
    var strStartDate = g_form.getValue('u_start_date');
    var objStartDate = new Date(strStartDate);

    var strEndDate = g_form.getValue('u_end_date');
    var objEndDate = new Date(strEndDate);

	// we will then compare both date objects
	if (objEndDate < objStartDate) {
		//If the end date is before the start date then and error msg is shown and the form is stopped from saving
		g_form.addErrorMessage(getMessage('start.date.validation.msg'));
		return false;
	}
}
